package com.eventstreaming.service;

import com.eventstreaming.model.Event;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducerService {

    private static final Logger logger = LoggerFactory.getLogger(EventProducerService.class);

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final ObjectMapper objectMapper;

    public EventProducerService(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    public void sendEvent(String topic, Event event) {
        try {
            String eventJson = objectMapper.writeValueAsString(event);
            CompletableFuture<SendResult<String, String>> future =
                    kafkaTemplate.send(topic, event.getId(), eventJson);

            future.whenComplete((result, ex) -> {
                if (ex == null) {
                    logger.info("Event sent successfully to topic [{}] with key [{}] at partition [{}] offset [{}]",
                            topic, event.getId(),
                            result.getRecordMetadata().partition(),
                            result.getRecordMetadata().offset());
                } else {
                    logger.error("Failed to send event to topic [{}] with key [{}]: {}",
                            topic, event.getId(), ex.getMessage());
                }
            });
        } catch (JsonProcessingException e) {
            logger.error("Error serializing event: {}", e.getMessage());
            throw new RuntimeException("Error serializing event", e);
        }
    }

    public void sendUserEvent(String payload) {
        Event event = new Event("USER_EVENT", "user-service", payload);
        sendEvent("user-events", event);
    }

    public void sendOrderEvent(String payload) {
        Event event = new Event("ORDER_EVENT", "order-service", payload);
        sendEvent("order-events", event);
    }

    public void sendNotificationEvent(String payload) {
        Event event = new Event("NOTIFICATION_EVENT", "notification-service", payload);
        sendEvent("notification-events", event);
    }
}

