package com.eventstreaming.controller;

import com.eventstreaming.model.Event;
import com.eventstreaming.service.EventProducerService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping("/publish")
    public ResponseEntity<Map<String, String>> publishEvent(
            @RequestParam String topic,
            @RequestBody Event event) {
        eventProducerService.sendEvent(topic, event);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of(
                        "status", "accepted",
                        "eventId", event.getId(),
                        "topic", topic
                ));
    }

    @PostMapping("/user")
    public ResponseEntity<Map<String, String>> publishUserEvent(@RequestBody Map<String, String> request) {
        String payload = request.getOrDefault("payload", "");
        eventProducerService.sendUserEvent(payload);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "topic", "user-events"));
    }

    @PostMapping("/order")
    public ResponseEntity<Map<String, String>> publishOrderEvent(@RequestBody Map<String, String> request) {
        String payload = request.getOrDefault("payload", "");
        eventProducerService.sendOrderEvent(payload);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "topic", "order-events"));
    }

    @PostMapping("/notification")
    public ResponseEntity<Map<String, String>> publishNotificationEvent(@RequestBody Map<String, String> request) {
        String payload = request.getOrDefault("payload", "");
        eventProducerService.sendNotificationEvent(payload);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "topic", "notification-events"));
    }
}

